/**
 * check-guidlines.js (Page)
 *
 * ============================================================================
 * IMPORTANT: ONLY FOR CLAUDE-GENERATED FILES
 * ============================================================================
 *
 * This validator should ONLY be run on files that were NEWLY GENERATED BY CLAUDE.
 *
 * Purpose:
 *   - Verify that Claude-generated page components follow all Page guidelines
 *   - Catch guideline violations before they enter the codebase
 *   - Ensure correct page type implementation (Overview, Dashboard, Object, Config)
 *
 * When to use:
 *   - After Claude generates a new page component
 *   - After Claude creates an overview, dashboard, object, or config page
 *   - After Claude modifies page inheritance or structure
 *
 * When NOT to use:
 *   - On existing legacy pages
 *   - On third-party or external code
 *
 * ============================================================================
 * AUTO-FIX WORKFLOW
 * ============================================================================
 *
 * This script will automatically:
 * 1. Scan for guideline violations
 * 2. Run fix-guidlines.js on files with errors
 * 3. Re-validate after fixing
 *
 * ============================================================================
 *
 * Architectural compliance checklist for all Page types.
 * This script is intended to be executed in a virtual environment.
 *
 * It scans the /pages folder, inspects page components, and reports
 * violations against the defined page architecture rules.
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const PAGES_DIR = path.resolve(process.cwd(), 'pages');
const FIX_SCRIPT = path.resolve(__dirname, 'fix-guidlines.js');

const filesWithErrors = new Set();

/**
 * Utility: report error
 */
function reportError(message, file) {
    console.error(`❌ ERROR: ${message}`);
    if (file) filesWithErrors.add(file);
}

/**
 * Utility: simple check wrapper
 */
function check(condition, message, file) {
    if (!condition) {
        reportError(message, file);
    }
}

/**
 * STEP 1: Discover page components
 */
function discoverPageFiles(dir) {
    if (!fs.existsSync(dir)) return [];

    return fs.readdirSync(dir)
        .filter(f => f.endsWith('.ts'))
        .map(f => path.join(dir, f));
}

/**
 * STEP 2: Read file content
 */
function readFile(filePath) {
    return fs.readFileSync(filePath, 'utf-8');
}

/**
 * STEP 3: Detect page type based on inheritance and template usage
 */
function detectPageType(tsContent, htmlContent) {
    if (tsContent.includes('extends ConfigPageComponent')) return 'config';
    if (tsContent.includes('extends ObjectPageComponent')) return 'object';
    if (htmlContent && htmlContent.includes('ui-object-navigation-main-page')) return 'overview';
    if (tsContent.includes('extends PageComponent')) return 'dashboard';
    return 'unknown';
}

/**
 * STEP 4: Run checks for a single page
 */
function runChecks(tsFile) {
    const baseName = tsFile.replace('.ts', '');
    const htmlFile = baseName + '.html';

    const tsContent = readFile(tsFile);
    const htmlContent = fs.existsSync(htmlFile) ? readFile(htmlFile) : '';

    const componentName = path.basename(tsFile);
    const pageType = detectPageType(tsContent, htmlContent);

    // Base rules (all pages)
    check(
        tsContent.includes('extends PageComponent') ||
        tsContent.includes('extends ConfigPageComponent') ||
        tsContent.includes('extends ObjectPageComponent'),
        `Component ${componentName} must inherit from PageComponent. See skill.md`,
        tsFile
    );

    check(
        tsContent.includes('super.ngOnInit'),
        `Component ${componentName} must call super.ngOnInit(). See skill.md`,
        tsFile
    );

    // STOP-AND-ASK rule
    check(
        pageType !== 'unknown',
        `Component ${componentName} does not clearly match a page type. STOP AND ASK. See skill.md`,
        tsFile
    );

    /**
     * OVERVIEW PAGE RULES
     */
    if (pageType === 'overview') {
        check(
            htmlContent.includes('ui-object-navigation-main-page'),
            `Overview Page ${componentName} must delegate rendering using <ui-object-navigation-main-page>. See overviewPage.md`,
            tsFile
        );

        check(
            !htmlContent.includes('<mvs-widget'),
            `Overview Page ${componentName} must not render widgets directly. See overviewPage.md`,
            tsFile
        );
    }

    /**
     * DASHBOARD PAGE RULES
     */
    if (pageType === 'dashboard') {
        check(
            tsContent.includes('WidgetFactory'),
            `Dashboard Page ${componentName} must create widgets via WidgetFactory. See dashboardPage.md`,
            tsFile
        );

        check(
            htmlContent.includes('onObjectSelect'),
            `Dashboard Page ${componentName} must handle onObjectSelect and navigate to Object Page. See dashboardPage.md`,
            tsFile
        );
    }

    /**
     * OBJECT PAGE RULES
     */
    if (pageType === 'object') {
        check(
            tsContent.includes('extends ObjectPageComponent'),
            `Object Page ${componentName} must extend ObjectPageComponent. See objectPage.md`,
            tsFile
        );

        check(
            tsContent.includes('getObjectType'),
            `Object Page ${componentName} must implement getObjectType(). See objectPage.md`,
            tsFile
        );

        check(
            htmlContent.includes('objectInplaceDirective'),
            `Object Page ${componentName} must contain ObjectInplaceDirective. See objectPage.md`,
            tsFile
        );
    }

    /**
     * CONFIG PAGE RULES
     */
    if (pageType === 'config') {
        check(
            tsContent.includes('navigationItems'),
            `Config Page ${componentName} must define navigationItems. See configPage.md`,
            tsFile
        );

        const tabCount = (htmlContent.match(/p-tab/g) || []).length;

        check(
            tabCount <= 3,
            `Config Page ${componentName} uses ${tabCount} tabs. If more than 3 entities exist, use object-based configuration components. See configPage.md`,
            tsFile
        );

        check(
            !htmlContent.includes('WidgetFactory.create'),
            `Config Page ${componentName} must not create widgets in template. See configPage.md`,
            tsFile
        );
    }
}

/**
 * Run validation on all page files
 */
function runValidation() {
    filesWithErrors.clear();

    const files = discoverPageFiles(PAGES_DIR);

    if (!files.length) {
        console.log('No page components found.');
        return 0;
    }

    files.forEach(runChecks);

    return filesWithErrors.size;
}

/**
 * MAIN EXECUTION
 */
function run() {
    console.log('🔍 Running page architecture checks...\n');

    let errorCount = runValidation();

    if (errorCount > 0) {
        console.log(`\n🔧 Found ${errorCount} file(s) with errors. Running auto-fix...\n`);

        // Run fix-guidlines.js for each file with errors
        for (const file of filesWithErrors) {
            console.log(`\n📄 Fixing: ${file}`);
            try {
                execSync(`node "${FIX_SCRIPT}" "${file}"`, { stdio: 'inherit' });
            } catch (e) {
                console.error(`Failed to fix ${file}: ${e.message}`);
            }
        }

        // Re-validate after fixing
        console.log('\n🔍 Re-validating after fixes...\n');
        errorCount = runValidation();

        if (errorCount > 0) {
            console.log(`\n⚠️  ${errorCount} file(s) still have errors after auto-fix.`);
            console.log('Manual intervention may be required for the remaining issues.');
        }
    }

    if (errorCount === 0) {
        console.log('\n✅ Page guideline check completed - all files pass!');
    } else {
        console.log('\n⚠️  Page guideline check completed with warnings.');
        process.exit(1);
    }
}

run();
